# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 0;

    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0)
        {
            health = 0;
            // Handle player death here
        }
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
    }

    public bool PurchaseItem(int price)
    {
        if (currency >= price)
        {
            currency -= price;
            return true; // Purchase successful
        }
        return false; // Not enough currency
    }
}

public class Shop : MonoBehaviour
{
    public int healthPotionPrice = 50;

    public void BuyHealthPotion(PlayerStats player)
    {
        if (player.PurchaseItem(healthPotionPrice))
        {
            player.health += 20; // Heal player
            if (player.health > 100)
            {
                player.health = 100; // Max health cap
            }
        }
    }
}

public class Game : MonoBehaviour
{
    private PlayerStats playerStats;

    void Start()
    {
        playerStats = new PlayerStats();
        playerStats.AddCurrency(100); // Starting currency
    }

    void Update()
    {
        // Example of taking damage
        if (Input.GetKeyDown(KeyCode.Space)) // Press space to take damage
        {
            playerStats.TakeDamage(10);
        }

        // Example of buying health potion
        if (Input.GetKeyDown(KeyCode.B)) // Press B to buy health potion
        {
            Shop shop = new Shop();
            shop.BuyHealthPotion(playerStats);
        }
    }
}